+/* === REP GROUPS === */
+.task-card .rep-indicator {
+  font-size: 10px;
+  color: var(--text-muted);
+  margin-left: auto;
+}
+
+.rep-list {
+  margin-top: 6px;
+  border-top: 1px solid var(--border);
+  padding-top: 4px;
+}
+
+.rep-item {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  padding: 3px 4px;
+  font-family: 'IBM Plex Mono', monospace;
+  font-size: 11px;
+  color: var(--text-dim);
+  cursor: pointer;
+  border-radius: 2px;
+}
+.rep-item:hover { background: var(--bg-4); }
+.rep-item.selected { background: var(--accent-dim); }
+
+.rep-dot {
+  width: 6px;
+  height: 6px;
+  border-radius: 50%;
+  flex-shrink: 0;
+}
+.rep-dot.pass { background: var(--pass); }
+.rep-dot.fail { background: var(--fail); }
+.rep-dot.running { background: var(--running); }
+.rep-dot.timeout { background: var(--timeout); }
+.rep-dot.error { background: var(--error); }
+
