+function groupTasksByName(taskList) {
+  const groups = new Map();
+  for (const t of taskList) {
+    if (!groups.has(t.name)) {
+      groups.set(t.name, []);
+    }
+    groups.get(t.name).push(t);
+  }
+  return groups;
+}
+
+function getGroupStatus(reps) {
+  const statuses = reps.map(r => r.status);
+  if (statuses.some(s => s === 'running')) return 'running';
+  if (statuses.every(s => s === 'pass')) return 'pass';
+  if (statuses.some(s => s === 'fail')) return 'fail';
+  if (statuses.some(s => s === 'timeout')) return 'timeout';
+  if (statuses.some(s => s === 'error')) return 'error';
+  return 'fail';
+}
+
+function toggleGroup(taskName) {
+  if (expandedGroups.has(taskName)) {
+    expandedGroups.delete(taskName);
+  } else {
+    expandedGroups.add(taskName);
+  }
+  renderTaskGrid();
+}
+
 function renderTaskGrid() {
   const grid = document.getElementById('taskGrid');
   const search = document.getElementById('searchInput').value.toLowerCase();
   let filtered = tasks;

-  if (currentFilter !== 'all') {
