     filtered = filtered.filter(t => t.name.toLowerCase().includes(search));
   }

+  // Group by task name
+  const groups = groupTasksByName(filtered);
+  let groupEntries = [];
+  for (const [name, reps] of groups) {
+    const passCount = reps.filter(r => r.status === 'pass').length;
+    const groupStatus = getGroupStatus(reps);
