+
+  // Filter by group status (or any rep matching for multi-rep)
+  if (currentFilter !== 'all') {
+    groupEntries = groupEntries.filter(g => {
+      if (g.reps.length === 1) return g.reps[0].status === currentFilter;
+      return g.groupStatus === currentFilter || g.reps.some(r => r.status === currentFilter);
+    });
+  }
+
   // Sort: fails first, then timeouts, then running, then pass
   const order = { fail: 0, timeout: 1, error: 2, running: 3, pass: 4 };
