+
+    // Multi-rep group
+    const expanded = expandedGroups.has(g.name);
+    const arrow = expanded ? '&#9660;' : '&#9654;';
+    const isSelected = g.reps.some(r => r.dir_name === currentTask);
+
+    let html = `
+      <div class="task-card ${g.groupStatus} ${isSelected ? 'selected' : ''}"
+           onclick="toggleGroup('${g.name}')">
+        <div class="name" title="${g.name}">${g.name}</div>
+        <div class="meta">
+          <span class="status-badge">${g.passCount}/${g.reps.length} pass</span>
+          <span class="rep-indicator">${arrow} ${g.reps.length} reps</span>
+        </div>`;
+
+    if (expanded) {
+      html += `<div class="rep-list">`;
+      for (const r of g.reps) {
+        const statusColor = { pass: 'var(--pass)', fail: 'var(--fail)', running: 'var(--running)', timeout: 'var(--timeout)', error: 'var(--error)' };
+        html += `
+          <div class="rep-item ${currentTask === r.dir_name ? 'selected' : ''}"
