+            <span class="rep-dot ${r.status}"></span>
+            <span style="min-width:42px;font-weight:500;text-transform:uppercase;font-size:10px;color:${statusColor[r.status] || 'var(--text-dim)'}">${r.status}</span>
+            <span style="color:var(--text-muted)">${r.hash.slice(0, 5)}</span>
+            <span>${r.sessions}s</span>
+            <span>${r.api_calls} calls</span>
+            ${r.total_tokens > 0 ? `<span>${(r.total_tokens/1000).toFixed(0)}k tok</span>` : ''}
+          </div>`;
+      }
+      html += `</div>`;
+    }
+
+    html += `</div>`;
+    return html;
+  }).join('');
 }

